def solve(challenges):
    # Assuming challenges is a list of dictionaries with challenge details
    results = []

    for challenge in challenges:
        if 'phase' in challenge:
            if challenge['phase'] == 'draft':
                challenge['phase'] = 'active'
            elif challenge['phase'] == 'active':
                challenge['phase'] = 'review'
            elif challenge['phase'] == 'review':
                challenge['phase'] = 'completed'
            results.append(challenge)

    return results
